// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// Replays pre-0.8 overflow: arithmetic happens inside `unchecked` so we can
/// mimic SafeMath's explicit guard and prove the require is what actually
/// stops the bug.
contract SafeMathReplay {
    mapping(address => uint256) public balanceOf;

    function setBalance(address who, uint256 amount) external { balanceOf[who] = amount; }

    function add(uint256 a, uint256 b) public pure returns (uint256 c) {
        [[SLOT unchecked_add]]
        [[SLOT overflow_check]]
    }

    function deposit(address to, uint256 amount) external {
        balanceOf[to] = add(balanceOf[to], amount);
    }
}
